module dram_cell (  
    input wire [15:0] data_in,  
    input wire rw,  
    input wire clk,  
    output reg [15:0] data_out  
);  
    reg [15:0] cell_data;  

    always @(posedge clk) begin  
        if (rw)  
            cell_data <= data_in;  
        else  
            data_out <= cell_data;  
    end  
endmodule
